head.b:skin:
/* ===== RESET & BASE ===== */
*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
body{font-family:'Noto Sans KR','Apple SD Gothic Neo',sans-serif;font-size:17px;line-height:1.85;color:#222;background:#f5f5f5}
a{color:#1a73e8;text-decoration:none}
a:hover{text-decoration:underline}
img{max-width:100%;height:auto}

/* ===== LAYOUT ===== */
.outer-wrapper{max-width:1160px;margin:0 auto;padding:0 16px}
.content-wrapper{display:grid;grid-template-columns:160px 1fr 300px;gap:20px;align-items:flex-start;margin-top:24px}
.main-content{min-width:0}
.sidebar-wrapper{min-width:0}

/* ===== 왼쪽 광고 ===== */
.ad-left-wrapper{width:160px}
.ad-left-sticky{position:sticky;top:80px;text-align:center;background:#fff;border-radius:8px;padding:10px 6px;box-shadow:0 1px 4px rgba(0,0,0,.08)}

/* ===== 글 목록 중간 광고 ===== */
.ad-mid-list{background:#fff;border-radius:8px;text-align:center;padding:14px;margin-bottom:20px;box-shadow:0 1px 4px rgba(0,0,0,.08)}

/* ===== HEADER ===== */
#header{background:#1a73e8;color:#fff;padding:0}
#header h1{font-size:22px;font-weight:700;padding:16px 0}
#header h1 a{color:#fff}
#header p.description{font-size:13px;opacity:.85;padding-bottom:14px}

/* ===== 헤더 광고 ===== */
.ad-header{background:#fff;text-align:center;padding:10px 0;border-bottom:1px solid #e0e0e0}

/* ===== NAV ===== */
nav.blog-nav{background:#155db2;padding:0 16px}
nav.blog-nav ul{display:flex;list-style:none;gap:0;max-width:1100px;margin:0 auto}
nav.blog-nav li a{display:block;padding:10px 14px;color:#fff;font-size:14px;font-weight:500}
nav.blog-nav li a:hover{background:rgba(255,255,255,.15);text-decoration:none}

/* ===== POST CARD (목록) ===== */
.post-outer{background:#fff;border-radius:8px;margin-bottom:20px;overflow:hidden;box-shadow:0 1px 4px rgba(0,0,0,.08)}
.post-title{font-size:20px;font-weight:700;padding:20px 20px 6px;line-height:1.4}
.post-title a{color:#1a1a1a}
.post-title a:hover{color:#1a73e8;text-decoration:none}
.post-meta{font-size:13px;color:#888;padding:0 20px 10px}
.post-body{padding:0 20px 20px;color:#333;line-height:1.9}
.post-body h2{font-size:19px;font-weight:700;margin:28px 0 10px;color:#1a1a1a;border-left:4px solid #1a73e8;padding-left:10px}
.post-body h3{font-size:16px;font-weight:700;margin:20px 0 8px;color:#333}
.post-body p{margin-bottom:14px}
.post-body ul,.post-body ol{margin:10px 0 16px 22px}
.post-body li{margin-bottom:6px}
.post-body table{width:100%;border-collapse:collapse;margin:16px 0;font-size:15px}
.post-body table th{background:#1a73e8;color:#fff;padding:10px 12px;text-align:left}
.post-body table td{padding:9px 12px;border-bottom:1px solid #e8e8e8}
.post-body table tr:nth-child(even){background:#f8f9ff}

/* ===== 신청 링크 섹션 ===== */
.post-body .apply-links{background:#e8f0fe;border-radius:8px;padding:18px 20px;margin:24px 0}
.post-body .apply-links h3{color:#1a73e8;margin-bottom:12px;font-size:16px}
.post-body .apply-links ul{margin-left:0;list-style:none}
.post-body .apply-links li{margin-bottom:10px;padding:10px 14px;background:#fff;border-radius:6px;border-left:3px solid #1a73e8}
.post-body .apply-links a{font-weight:700;font-size:15px;color:#1a73e8}
.post-body .apply-links a:hover{text-decoration:underline}

/* ===== 인아티클 광고 ===== */
.ad-in-article{text-align:center;margin:28px 0;padding:10px;background:#fafafa;border-top:1px solid #eee;border-bottom:1px solid #eee}
.ad-label{font-size:11px;color:#aaa;margin-bottom:4px}

/* ===== 포스트 하단 광고 ===== */
.ad-post-footer{text-align:center;margin:28px 0}

/* ===== LABEL (태그) ===== */
.post-labels{padding:8px 20px 16px;font-size:13px}
.post-labels span{margin-right:4px;color:#888}
.post-labels a{display:inline-block;background:#e8f0fe;color:#1a73e8;border-radius:20px;padding:3px 10px;font-size:12px;margin:2px}
.post-labels a:hover{background:#1a73e8;color:#fff;text-decoration:none}

/* ===== SIDEBAR ===== */
.sidebar-wrapper .widget{background:#fff;border-radius:8px;padding:18px;margin-bottom:18px;box-shadow:0 1px 4px rgba(0,0,0,.07)}
.sidebar-wrapper h2.title{font-size:15px;font-weight:700;color:#1a1a1a;border-bottom:2px solid #1a73e8;padding-bottom:8px;margin-bottom:12px}
.sidebar-wrapper .widget ul{list-style:none}
.sidebar-wrapper .widget li{padding:7px 0;border-bottom:1px solid #f0f0f0;font-size:14px}
.sidebar-wrapper .widget li:last-child{border:none}
.ad-sidebar{text-align:center}

/* ===== PAGINATION ===== */
.blog-pager{text-align:center;padding:20px 0}
.blog-pager a{display:inline-block;padding:9px 22px;background:#1a73e8;color:#fff;border-radius:4px;font-size:14px;margin:4px}
.blog-pager a:hover{background:#155db2;text-decoration:none}

/* ===== FOOTER ===== */
#footer{background:#222;color:#aaa;text-align:center;padding:24px 16px;margin-top:40px;font-size:13px}
#footer a{color:#888}

/* ===== RESPONSIVE ===== */
@media(max-width:900px){
  .content-wrapper{grid-template-columns:1fr 280px}
  .ad-left-wrapper{display:none}
}
@media(max-width:640px){
  .content-wrapper{grid-template-columns:1fr}
  .sidebar-wrapper{display:none}
  .post-title{font-size:18px}
  .post-body h2{font-size:17px}
  nav.blog-nav ul{flex-wrap:wrap}
}

body.script:
// 글 목록 중간 광고: 3번째 포스트 뒤로 이동
document.addEventListener('DOMContentLoaded', function() {
  var posts = document.querySelectorAll('.post-outer');
  var ad = document.getElementById('mid-list-ad');
  if (!ad) return;
  var insertAfter = Math.min(2, posts.length - 1); // 3번째 글(index 2) 뒤
  if (posts.length >= 3) {
    posts[insertAfter].insertAdjacentElement('afterend', ad);
    ad.style.display = 'block';
  }
});
